content:
{
  "sentences": [
    {
      "text": "要不然我們去這家餐廳，要不然就去那家小吃店。",
      "pinyin": "Yàobùrán wǒmen qù zhè jiā cāntīng, yàobùrán jiù qù nà jiā xiǎochī diàn.",
      "pinyin_numeric": "yao4bu4ran2 wo3men qu4 zhe4 jia1 can1ting1, yao4bu4ran2 jiu4 qu4 na4 jia1 xiao3chi1 dian4.",
      "translation_en": "Either we go to this restaurant, or we go to that snack shop.",
      "translation_ko": "우리는 이 식당에 가거나, 아니면 저 간식 가게에 가요."
    },
    {
      "text": "要不然我們約六點，要不然就約七點半。",
      "pinyin": "Yàobùrán wǒmen yuē liù diǎn, yàobùrán jiù yuē qī diǎn bàn.",
      "pinyin_numeric": "yao4bu4ran2 wo3men yue1 liu4 dian3, yao4bu4ran2 jiu4 yue1 qi1 dian3 ban4.",
      "pinyin_en": "Either we meet at six, or we meet at seven thirty.",
      "translation_ko": "우리는 6시에 만나거나, 아니면 7시 30분에 만나요."
    },
    {
      "text": "要不然走這條路線，要不然就走那條路線。",
      "pinyin": "Yàobùrán zǒu zhè tiáo lùxiàn, yàobùrán jiù zǒu nà tiáo lùxiàn.",
      "pinyin_numeric": "yao4bu4ran2 zou3 zhe4 tiao2 lu4xian4, yao4bu4ran2 jiu4 zou3 na4 tiao2 lu4xian4.",
      "pinyin_en": "Either take this route, or take that route.",
      "translation_ko": "이 경로로 가거나, 아니면 저 경로로 가요."
    },
    {
      "text": "要不然你選這個，要不然就選那個。",
      "pinyin": "Yàobùrán nǐ xuǎn zhège, yàobùrán jiù xuǎn nàge.",
      "pinyin_numeric": "yao4bu4ran2 ni3 xuan3 zhe4ge, yao4bu4ran2 jiu4 xuan3 na4ge.",
      "pinyin_en": "Either you choose this one, or you choose that one.",
      "translation_ko": "이것을 선택하거나, 아니면 저것을 선택하세요."
    },
    {
      "text": "要不然我們提早出發，要不然就延後碰面。",
      "pinyin": "Yàobùrán wǒmen tízǎo chūfā, yàobùrán jiù yánhòu pèngmiàn.",
      "pinyin_numeric": "yao4bu4ran2 wo3men ti2zao3 chu1fa1, yao4bu4ran2 jiu4 yan2hou4 peng4mian4.",
      "pinyin_en": "Either we leave early, or we postpone the meeting.",
      "translation_ko": "우리는 일찍 출발하거나, 아니면 만남을 연기해요."
    },
    {
      "text": "要不然取消訂位，要不然就改時間。",
      "pinyin": "Yàobùrán qǔxiāo dìngwèi, yàobùrán jiù gǎi shíjiān.",
      "pinyin_numeric": "yao4bu4ran2 qu3xiao1 ding4wei4, yao4bu4ran2 jiu4 gai3 shi2jian1.",
      "pinyin_en": "Either cancel the reservation, or change the time.",
      "translation_ko": "예약을 취소하거나, 아니면 시간을 변경해요."
    },
    {
      "text": "要不然你考慮一下，要不然就馬上決定。",
      "pinyin": "Yàobùrán nǐ kǎolǜ yīxià, yàobùrán jiù mǎshàng juédìng.",
      "pinyin_numeric": "yao4bu4ran2 ni3 kao3lv4 yi1xia4, yao4bu4ran2 jiu4 ma3shang4 jue2ding4.",
      "pinyin_en": "Either you think about it, or decide right away.",
      "translation_ko": "생각해 보거나, 아니면 바로 결정하세요."
    },
    {
      "text": "要不然我們直達，要不然就轉車。",
      "pinyin": "Yàobùrán wǒmen zhídá, yàobùrán jiù zhuǎn chē.",
      "pinyin_numeric": "yao4bu4ran2 wo3men zhi2da2, yao4bu4ran2 jiu4 zhuan3 che1.",
      "pinyin_en": "Either we go direct, or we transfer.",
      "translation_ko": "우리는 직행으로 가거나, 아니면 환승해요."
    },
    {
      "text": "要不然你問路，要不然就用導航。",
      "pinyin": "Yàobùrán nǐ wèn lù, yàobùrán jiù yòng dǎoháng.",
      "pinyin_numeric": "yao4bu4ran2 ni3 wen4 lu4, yao4bu4ran2 jiu4 yong4 dao3hang2.",
      "pinyin_en": "Either you ask for directions, or use the navigation.",
      "translation_ko": "길을 물어보거나, 아니면 내비게이션을 사용하세요."
    },
    {
      "text": "要不然我們在路口碰面，要不然就在捷運站出口。",
      "pinyin": "Yàobùrán wǒmen zài lùkǒu pèngmiàn, yàobùrán jiù zài jiéyùn zhàn chūkǒu.",
      "pinyin_numeric": "yao4bu4ran2 wo3men zai4 lu4kou3 peng4mian4, yao4bu4ran2 jiu4 zai4 jie2yun4 zhan4 chu1kou3.",
      "pinyin_en": "Either we meet at the intersection, or at the MRT station exit.",
      "translation_ko": "우리는 교차로에서 만나거나, 아니면 지하철역 출구에서 만나요."
    }
  ]
}
